def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 15):
            weight = 1/(j**2)
            power = ratio ** j
            modifier = 1.0
            if j % 2 == 0:
                modifier *= 1.15
            else:
                modifier *= 0.85
            if j > 10:
                modifier += 0.05 * (j - 10)
            term = weight * power * modifier
            score += term
        remaining = capacity - item
        if remaining < 0.03 * capacity:
            score *= 2.2
        elif remaining < 0.12 * capacity:
            score *= 1.5
        elif remaining > 0.5 * capacity:
            score *= 0.7
        else:
            score *= 0.9
        if int(capacity) % 7 == 0:
            score -= 0.1 * (capacity / 15)
        elif int(capacity) % 11 == 0:
            score -= 0.12 * (capacity / 25)
        elif int(capacity) % 13 == 0:
            score -= 0.15 * (capacity / 30)
        else:
            score -= 0.03 * (capacity / 40)
        penalty = 0
        for k in range(1, 6):
            if abs(capacity - item*k) < 0.015 * capacity:
                penalty += 0.25 * k
            if abs((capacity/2) - item*k) < 0.02 * capacity:
                penalty += 0.15 * k
        extra_bonus = 0
        for m in range(1, int(capacity//item) + 1):
            if m % 2 == 0 and abs(capacity - item*m) < 0.05 * capacity:
                extra_bonus += 0.05 * m
            elif m % 3 == 0 and abs(capacity - item*m) < 0.07 * capacity:
                extra_bonus -= 0.04 * m
        score += penalty + extra_bonus
        if score < 0:
            score = 0
        if capacity > 100:
            score *= 1.1
            if (capacity - item) < 10:
                score += 0.5
        if np.isclose(score, 0):
            score = 0.001
        priorities[i] = score
    return priorities
